def _g(obj, key):
	try:
		return obj[key]
	except Exception:
		return None
header = currentValue.value if currentValue is not None else None
hdrId = _g(header, 'Id') if header is not None else None
BlueRidge.Common.Util.log('selectedHeader.onChange hdrId=%s' % hdrId)
if not hdrId or hdrId <= 0:
	if self.view.custom.mode == 'draft':
		self.view.custom.draftId = 0
		self.view.custom.draftEditDraft = {'Id': 0, 'Name': '', 'EffectiveFrom': '', 'steps': []}
		self.view.custom.draftSelected = {'Id': 0, 'Name': '', 'EffectiveFrom': '', 'steps': []}
		self.view.custom.mode = 'view'
		self.view.rootContainer.broadcastDirty(False)
	return
publishedAt = _g(header, 'PublishedAt')
deprecatedAt = _g(header, 'DeprecatedAt')
isDraft = (publishedAt is None) and (deprecatedAt is None)
BlueRidge.Common.Util.log('selectedHeader.onChange isDraft=%s publishedAt=%s deprecatedAt=%s' % (isDraft, publishedAt, deprecatedAt))
if isDraft:
	if self.view.custom.draftId == hdrId:
		return
	name = _g(header, 'Name') or ''
	effRaw = _g(header, 'EffectiveFrom')
	effStr = str(effRaw or '')[:10]
	steps = BlueRidge.Parts.RouteTemplate.getSteps(hdrId) or []
	stepsCopy = [dict(s) for s in steps]
	self.view.custom.draftId = hdrId
	self.view.custom.draftEditDraft = {'Id': hdrId, 'Name': name, 'EffectiveFrom': effStr, 'steps': stepsCopy}
	self.view.custom.draftSelected = {'Id': hdrId, 'Name': name, 'EffectiveFrom': effStr, 'steps': [dict(s) for s in steps]}
	self.view.custom.mode = 'draft'
	self.view.rootContainer.broadcastDirty(False)
else:
	if self.view.custom.mode == 'draft':
		self.view.custom.draftId = 0
		self.view.custom.draftEditDraft = {'Id': 0, 'Name': '', 'EffectiveFrom': '', 'steps': []}
		self.view.custom.draftSelected = {'Id': 0, 'Name': '', 'EffectiveFrom': '', 'steps': []}
		self.view.custom.mode = 'view'
		self.view.rootContainer.broadcastDirty(False)

newId = currentValue.value if currentValue is not None else 0
BlueRidge.Common.Util.log('selectedVersionId.onChange newId=%s currentMode=%s currentDraftId=%s' % (newId, self.view.custom.mode, self.view.custom.draftId))
if not newId or newId <= 0:
	if self.view.custom.mode == 'draft':
		self.view.custom.draftId = 0
		self.view.custom.draftEditDraft = {'Id': 0, 'Name': '', 'EffectiveFrom': '', 'steps': []}
		self.view.custom.draftSelected = {'Id': 0, 'Name': '', 'EffectiveFrom': '', 'steps': []}
		self.view.custom.mode = 'view'
		self.view.rootContainer.broadcastDirty(False)
	return
header = BlueRidge.Parts.RouteTemplate.getHeader(newId)
if not header:
	BlueRidge.Common.Util.log('selectedVersionId.onChange getHeader returned None for newId=%s' % newId)
	return
publishedAt = header.get('PublishedAt')
deprecatedAt = header.get('DeprecatedAt')
isDraft = (publishedAt is None) and (deprecatedAt is None)
BlueRidge.Common.Util.log('selectedVersionId.onChange isDraft=%s publishedAt=%s deprecatedAt=%s' % (isDraft, publishedAt, deprecatedAt))
if isDraft:
	if self.view.custom.draftId == newId:
		return
	name = header.get('Name') or ''
	effStr = str(header.get('EffectiveFrom') or '')[:10]
	steps = BlueRidge.Parts.RouteTemplate.getSteps(newId) or []
	stepsCopy = [dict(s) for s in steps]
	self.view.custom.draftId = newId
	self.view.custom.draftEditDraft = {'Id': newId, 'Name': name, 'EffectiveFrom': effStr, 'steps': stepsCopy}
	self.view.custom.draftSelected = {'Id': newId, 'Name': name, 'EffectiveFrom': effStr, 'steps': [dict(s) for s in steps]}
	self.view.custom.mode = 'draft'
	self.view.rootContainer.broadcastDirty(False)
else:
	if self.view.custom.mode == 'draft':
		self.view.custom.draftId = 0
		self.view.custom.draftEditDraft = {'Id': 0, 'Name': '', 'EffectiveFrom': '', 'steps': []}
		self.view.custom.draftSelected = {'Id': 0, 'Name': '', 'EffectiveFrom': '', 'steps': []}
		self.view.custom.mode = 'view'
		self.view.rootContainer.broadcastDirty(False)

